 25	sm_ag_if_ans_t write_ctrl_rc_sm(void const* data)
 26	{
 27	  assert(data != NULL);
 28	//  assert(data->type == RAN_CONTROL_CTRL_V1_03 );
 29	
 30	  rc_ctrl_req_data_t const* ctrl = (rc_ctrl_req_data_t const*)data;
 31	  if(ctrl->hdr.format == FORMAT_1_E2SM_RC_CTRL_HDR){
 32	    if(ctrl->hdr.frmt_1.ric_style_type == 1 && ctrl->hdr.frmt_1.ctrl_act_id == 2){
 33	      printf("QoS flow mapping configuration \n");
 34	      e2sm_rc_ctrl_msg_frmt_1_t const* frmt_1 = &ctrl->msg.frmt_1;
 35	      for(size_t i = 0; i < frmt_1->sz_ran_param; ++i){
 36	        seq_ran_param_t const* rp = frmt_1->ran_param;
 37	        if(rp[i].ran_param_id == 1){
 38	          assert(rp[i].ran_param_val.type == ELEMENT_KEY_FLAG_TRUE_RAN_PARAMETER_VAL_TYPE );
 39	          printf("DRB ID %ld \n", rp[i].ran_param_val.flag_true->int_ran);
 40	        } else if(rp[i].ran_param_id == 2){
 41	          assert(rp[i].ran_param_val.type == LIST_RAN_PARAMETER_VAL_TYPE);
 42	          printf("List of QoS Flows to be modified \n");
 43	          for(size_t j = 0; j < ctrl->msg.frmt_1.ran_param[i].ran_param_val.lst->sz_lst_ran_param; ++j){ 
 44	            lst_ran_param_t const* lrp = rp[i].ran_param_val.lst->lst_ran_param;
 45	            // The following assertion should be true, but there is a bug in the std
 46	            // check src/sm/rc_sm/enc/rc_enc_asn.c:1085 and src/sm/rc_sm/enc/rc_enc_asn.c:984 
 47	            // assert(lrp[j].ran_param_id == 3); 
 48	            assert(lrp[j].ran_param_struct.ran_param_struct[0].ran_param_id == 4) ;
 49	            assert(lrp[j].ran_param_struct.ran_param_struct[0].ran_param_val.type == ELEMENT_KEY_FLAG_TRUE_RAN_PARAMETER_VAL_TYPE);
 50	
 51	            int64_t qfi = lrp[j].ran_param_struct.ran_param_struct[0].ran_param_val.flag_true->int_ran;
 52	            assert(qfi > -1 && qfi < 65);
 53	
 54	            assert(lrp[j].ran_param_struct.ran_param_struct[1].ran_param_id == 5);
 55	            assert(lrp[j].ran_param_struct.ran_param_struct[1].ran_param_val.type == ELEMENT_KEY_FLAG_FALSE_RAN_PARAMETER_VAL_TYPE);
 56	            int64_t dir = lrp[j].ran_param_struct.ran_param_struct[1].ran_param_val.flag_false->int_ran;
 57	            assert(dir == 0 || dir == 1);
 58	            printf("qfi = %ld dir %ld \n", qfi, dir);
 59	          }
 60	        } 
 61	      }
 62	    }
 63	  }
 64	
 65	  sm_ag_if_ans_t ans = {.type = CTRL_OUTCOME_SM_AG_IF_ANS_V0};
 66	  ans.ctrl_out.type = RAN_CTRL_V1_3_AGENT_IF_CTRL_ANS_V0;
 67	  return ans;
 68	}
