161	
162	    kpm->ind.hdr = fill_kpm_ind_hdr_sta(); 
163	    // 7.8 Supported RIC Styles and E2SM IE Formats
164	    // Format 4 corresponds to indication message 3
165	    kpm->ind.msg.type = FORMAT_3_INDICATION_MESSAGE;
166	    kpm->ind.msg.frm_3 = fill_kpm_ind_msg_frm_3_sta();
167	  } else {
168	     kpm->ind.hdr = fill_kpm_ind_hdr(); 
169	     kpm->ind.msg = fill_kpm_ind_msg(); 
170	  }
171	}
